<?php

namespace Database\Seeders;

use App\Models\Category;
use App\Models\Choice;
use App\Models\Quiz;
use App\Models\Term;
use Illuminate\Database\Seeder;

class AdditionalTermSeeder extends Seeder
{
    public function run(): void
    {
        $data = $this->networkTerms()
            + $this->securityTerms()
            + $this->databaseTerms()
            + $this->algorithmTerms()
            + $this->cloudTerms()
            + $this->webTerms()
            + $this->programmingTerms()
            + $this->osLinuxTerms();

        foreach ($data as $slug => $terms) {
            $cat = Category::where('slug', $slug)->first();
            if (!$cat) continue;
            foreach ($terms as $t) {
                $term = Term::updateOrCreate(
                    ['name' => $t['name'], 'category_id' => $cat->id],
                    [
                        'definition' => $t['definition'],
                        'example'    => $t['example'] ?? null,
                        'difficulty' => $t['difficulty'],
                    ]
                );
                if (!empty($t['quiz'])) {
                    $quiz = Quiz::updateOrCreate(
                        ['term_id' => $term->id, 'question' => $t['quiz']['question']],
                        ['explanation' => $t['quiz']['explanation']]
                    );
                    foreach ($t['quiz']['choices'] as $c) {
                        Choice::updateOrCreate(
                            ['quiz_id' => $quiz->id, 'body' => $c['body']],
                            ['is_correct' => $c['is_correct']]
                        );
                    }
                }
            }
        }
    }

