            ['name'=>'最小権限の原則','definition'=>'ユーザー・プロセス・システムに対し、必要最低限の権限のみを付与するセキュリティ原則。侵害時の被害を最小化する。','example'=>'アプリのDBユーザーにはSELECT・INSERT・UPDATEのみ付与し、DROP・TRUNCATE権限は与えない。','difficulty'=>3,'quiz'=>['question'=>'最小権限の原則を適用する主な目的はどれか？','explanation'=>'最小権限により、アカウントやシステムが侵害された場合でも攻撃者が行える操作を最小化し被害を限定できる。','choices'=>[['body'=>'システムのパフォーマンスを向上させる','is_correct'=>false],['body'=>'侵害時の被害を最小化する','is_correct'=>true],['body'=>'ログイン速度を上げる','is_correct'=>false],['body'=>'パスワードを不要にする','is_correct'=>false]]]],
            ['name'=>'インシデントレスポンス','definition'=>'セキュリティインシデント（侵害・感染・漏洩等）発生時に行う対応プロセス。準備・検知・封じ込め・根絶・復旧・教訓の6フェーズ。','example'=>'ランサムウェア感染を検知後、感染端末をネットワークから隔離（封じ込め）し、被害範囲を調査して復旧する。','difficulty'=>4,'quiz'=>['question'=>'インシデントレスポンスにおける「封じ込め」の目的はどれか？','explanation'=>'封じ込めは被害の拡大を防ぐため、感染端末のネットワーク切断や該当サービスの停止など即時措置を行うフェーズ。','choices'=>[['body'=>'根本原因を特定する','is_correct'=>false],['body'=>'被害の拡大を防止する','is_correct'=>true],['body'=>'システムを復旧する','is_correct'=>false],['body'=>'再発防止策を策定する','is_correct'=>false]]]],
            ['name'=>'サンドボックス','definition'=>'外部環境から隔離された安全な実行環境。不審なプログラムの動作を安全に分析したり、未知マルウェアを検知するために使う。','example'=>'セキュリティソフトが受信メールの添付ファイルをサンドボックスで自動実行し、マルウェアか判定する。','difficulty'=>3,'quiz'=>['question'=>'セキュリティにおけるサンドボックスの主な用途はどれか？','explanation'=>'サンドボックスは隔離環境でプログラムを実行し、実際のシステムに影響を与えずにマルウェアかどうかを分析できる。','choices'=>[['body'=>'パスワードを安全に保管する','is_correct'=>false],['body'=>'隔離環境で不審なプログラムを安全に実行・分析する','is_correct'=>true],['body'=>'通信を暗号化する','is_correct'=>false],['body'=>'ファイアウォールのルールを管理する','is_correct'=>false]]]],
            ['name'=>'SSL証明書（TLS証明書）','definition'=>'Webサイトの身元を証明し、HTTPS通信を可能にするデジタル証明書。CAが発行し、有効期限がある。','example'=>'ブラウザのアドレスバーの鍵マークをクリックすると、そのサイトのSSL証明書の発行者や有効期限を確認できる。','difficulty'=>2,'quiz'=>['question'=>'SSL証明書の有効期限が切れたWebサイトにアクセスするとどうなるか？','explanation'=>'証明書の有効期限切れはブラウザが警告を表示する。証明書の有効性を確認できないためHTTPS通信の信頼性が失われる。','choices'=>[['body'=>'自動更新される','is_correct'=>false],['body'=>'ブラウザが警告を表示する','is_correct'=>true],['body'=>'HTTP通信に自動切替される','is_correct'=>false],['body'=>'接続が完全に不可能になる','is_correct'=>false]]]],
            ['name'=>'SAML（Security Assertion Markup Language）','definition'=>'ID プロバイダーとサービスプロバイダー間でユーザー認証情報をXMLで交換するシングルサインオン（SSO）の標準プロトコル。','example'=>'会社のAD（Active Directory）をIdPとしてSAMLを使い、G SuiteやSalesforceにSSOでアクセスする。','difficulty'=>4,'quiz'=>['question'=>'SAMLの主な用途はどれか？','explanation'=>'SAMLはエンタープライズ環境でのシングルサインオン（SSO）に広く使われ、IDプロバイダーとサービス間で認証アサーションを交換する。','choices'=>[['body'=>'APIの認可管理','is_correct'=>false],['body'=>'エンタープライズSSOのための認証情報交換','is_correct'=>true],['body'=>'パスワードのハッシュ化','is_correct'=>false],['body'=>'ネットワーク暗号化','is_correct'=>false]]]],
            ['name'=>'CSIRT（Computer Security Incident Response Team）','definition'=>'セキュリティインシデントへの対応を専門に行う組織またはチーム。社内CSIRTと国家CSIRTがある。','example'=>'企業がCSIRTを設置し、マルウェア感染やサイバー攻撃発生時に迅速な対応・復旧・情報共有を行う。','difficulty'=>3,'quiz'=>['question'=>'CSIRTの主な役割はどれか？','explanation'=>'CSIRTはインシデントの検知・トリアージ・対応・復旧を行い、再発防止や関係機関との情報共有も担う。','choices'=>[['body'=>'新機能の開発','is_correct'=>false],['body'=>'セキュリティインシデントへの対応と復旧','is_correct'=>true],['body'=>'ネットワークの設計','is_correct'=>false],['body'=>'ユーザー管理','is_correct'=>false]]]],
        ]];
