    private function databaseTerms(): array
    {
        return ['database' => [
            ['name'=>'FOREIGN KEY（外部キー）','definition'=>'他テーブルのPRIMARY KEYを参照する制約。参照整合性を保ち、孤立レコードの発生を防ぐ。','example'=>'ordersテーブルのuser_id列にFOREIGN KEY制約を設け、usersテーブルに存在しないuser_idを登録不可にする。','difficulty'=>2,'quiz'=>['question'=>'FOREIGN KEY制約の主な目的はどれか？','explanation'=>'外部キー制約により参照先に存在しないデータの挿入や、参照中データの削除を防ぎ参照整合性を維持する。','choices'=>[['body'=>'検索速度を向上させる','is_correct'=>false],['body'=>'参照整合性を維持する','is_correct'=>true],['body'=>'値を一意にする','is_correct'=>false],['body'=>'NULLを禁止する','is_correct'=>false]]]],
            ['name'=>'JOIN（テーブル結合）','definition'=>'複数テーブルの行を関連する列で結合して1つの結果セットを作る操作。INNER・LEFT・RIGHT・FULL JOINがある。','example'=>'SELECT u.name, o.amount FROM users u INNER JOIN orders o ON u.id = o.user_id;','difficulty'=>2,'quiz'=>['question'=>'INNER JOINの特徴として正しいものはどれか？','explanation'=>'INNER JOINは両方のテーブルで結合条件を満たす行のみを返す。どちらかにしか存在しない行は含まれない。','choices'=>[['body'=>'左テーブルの全行を返す','is_correct'=>false],['body'=>'両テーブルで結合条件を満たす行のみ返す','is_correct'=>true],['body'=>'両テーブルの全行を返す','is_correct'=>false],['body'=>'右テーブルの全行を返す','is_correct'=>false]]]],
            ['name'=>'VIEW（ビュー）','definition'=>'SELECT文を名前付きで保存した仮想テーブル。実データは持たないが通常テーブルのように参照できる。','example'=>'頻繁に使う複雑な結合クエリをVIEWとして定義し、以降は「SELECT * FROM v_active_users」で取得する。','difficulty'=>2,'quiz'=>['question'=>'VIEWに関する説明として正しいものはどれか？','explanation'=>'VIEWは実データを持たず、参照時にベースクエリが実行される仮想テーブル。クエリの再利用やアクセス制御に利用される。','choices'=>[['body'=>'独自のデータを物理的に保持する','is_correct'=>false],['body'=>'実データを持たない仮想テーブル','is_correct'=>true],['body'=>'インデックスを使えない','is_correct'=>false],['body'=>'更新操作ができない','is_correct'=>false]]]],
            ['name'=>'ストアドプロシージャ','definition'=>'DBサーバー上に保存・実行できるプログラムの塊。複数SQL操作をひとまとめにしてアプリから呼び出せる。','example'=>'発注処理（在庫減算→発注レコード挿入→通知）をストアドプロシージャにまとめ、CALL place_order(user_id, item_id)で実行する。','difficulty'=>3,'quiz'=>['question'=>'ストアドプロシージャのメリットとして正しいものはどれか？','explanation'=>'ストアドプロシージャはDB側で事前コンパイルされ、ネットワーク往復を減らし複数SQL操作をまとめて高速実行できる。','choices'=>[['body'=>'テーブルを物理的に結合できる','is_correct'=>false],['body'=>'複数のSQL処理をまとめてDB側で実行できる','is_correct'=>true],['body'=>'データを暗号化できる','is_correct'=>false],['body'=>'自動的にバックアップを取る','is_correct'=>false]]]],
            ['name'=>'トリガー','definition'=>'テーブルへのINSERT・UPDATE・DELETE操作時に自動実行されるプログラム。データ整合性の維持や監査ログに使う。','example'=>'ordersテーブルにINSERTされると自動でAFTER INSERTトリガーが起動し、inventoryの在庫数を自動更新する。','difficulty'=>3,'quiz'=>['question'=>'トリガーが自動実行されるのはどのような時か？','explanation'=>'トリガーはテーブルに対するDML操作（INSERT・UPDATE・DELETE）の前後に自動的に実行されるDB側のプログラム。','choices'=>[['body'=>'定時スケジュールで実行される','is_correct'=>false],['body'=>'テーブルへのDML操作（INSERT/UPDATE/DELETE）時','is_correct'=>true],['body'=>'クライアント接続時','is_correct'=>false],['body'=>'バックアップ実行時','is_correct'=>false]]]],
            ['name'=>'デッドロック','definition'=>'2つ以上のトランザクションがお互いのロック解放を待って永遠に待機し合う状態。DBMSが検知してどちらかをロールバックする。','example'=>'Txn1がAをロックしBを待ち、Txn2がBをロックしAを待つ状態がデッドロック。DBが一方を強制ロールバックして解消する。','difficulty'=>4,'quiz'=>['question'=>'デッドロック発生時にDBMSが取る対応として正しいものはどれか？','explanation'=>'DBMSはデッドロックを検知すると関係するトランザクションのうち1つを強制的にロールバックし、ロックを解放する。','choices'=>[['body'=>'全トランザクションをコミットする','is_correct'=>false],['body'=>'いずれかのトランザクションを強制ロールバックする','is_correct'=>true],['body'=>'データベースを再起動する','is_correct'=>false],['body'=>'ロックを全て解放する','is_correct'=>false]]]],
            ['name'=>'MVCC（多版型同時実行制御）','definition'=>'読み取り操作のたびにデータのスナップショットを提供し、読み書きが互いにブロックしないようにする同時実行制御方式。','example'=>'PostgreSQLとMySQLのInnoDBがMVCCを採用。長時間トランザクションでも読み取りがロックされない。','difficulty'=>5,'quiz'=>['question'=>'MVCCの主なメリットはどれか？','explanation'=>'MVCCにより読み取りが書き込みをブロックしないため、読み書きが高い同時実行性で処理できる。','choices'=>[['body'=>'ディスク使用量を削減する','is_correct'=>false],['body'=>'読み取りと書き込みが互いにブロックしない','is_correct'=>true],['body'=>'データを暗号化する','is_correct'=>false],['body'=>'自動的にインデックスを最適化する','is_correct'=>false]]]],
            ['name'=>'レプリケーション','definition'=>'DBのデータを複数サーバーにリアルタイムで複製する技術。読み取り負荷分散・高可用性・バックアップ目的で使われる。','example'=>'プライマリDBへの書き込みが自動的に2台のレプリカDBに同期され、読み取りクエリはレプリカに振り分ける。','difficulty'=>3,'quiz'=>['question'=>'DBレプリケーションの主な目的はどれか？','explanation'=>'レプリケーションはデータを複数サーバーに複製することで、読み取り負荷分散・フェイルオーバー対応・データ保護を実現する。','choices'=>[['body'=>'クエリを高速化する専用機能','is_correct'=>false],['body'=>'高可用性と読み取り負荷分散のためのデータ複製','is_correct'=>true],['body'=>'不要データを自動削除する','is_correct'=>false],['body'=>'テーブルを自動正規化する','is_correct'=>false]]]],
            ['name'=>'シャーディング','definition'=>'大量データを複数DBに水平分割して格納・管理する手法。1台のDBに収まらないスケールアウトに使われる。','example'=>'ユーザーIDのmod 4でDBを4台に分散し、user_id=101はDB1、user_id=102はDB2という具合に分割する。','difficulty'=>4,'quiz'=>['question'=>'シャーディングの主な目的はどれか？','explanation'=>'シャーディングはデータを複数DBに水平分割することで、1台に収まらない大量データを分散処理・管理するスケーリング手法。','choices'=>[['body'=>'データを暗号化する','is_correct'=>false],['body'=>'大量データを複数DBに水平分割してスケールアウト','is_correct'=>true],['body'=>'バックアップを自動化する','is_correct'=>false],['body'=>'クエリ文を最適化する','is_correct'=>false]]]],
            ['name'=>'NoSQL','definition'=>'リレーショナルDBとは異なるデータモデルを持つDB群の総称。ドキュメント型・KV型・グラフ型・列指向型などがある。','example'=>'MongoDBはドキュメント型NoSQL。JSONに似た柔軟なスキーマでデータを格納し、スケールアウトに強い。','difficulty'=>3,'quiz'=>['question'=>'NoSQLデータベースの特徴として正しいものはどれか？','explanation'=>'多くのNoSQLはスキーマが固定されていない（スキーマレス）ため、データ構造を柔軟に変更できる。','choices'=>[['body'=>'必ずSQLで操作する','is_correct'=>false],['body'=>'スキーマレスで柔軟なデータ構造を持てる','is_correct'=>true],['body'=>'ACID特性を必ず保証する','is_correct'=>false],['body'=>'テーブルと行で構成される','is_correct'=>false]]]],
            ['name'=>'Redis','definition'=>'インメモリのKVS（Key-Value Store）型NoSQL。高速なキャッシュ・セッション管理・Pub/Subメッセージングなどに使われる。','example'=>'LaravelでRedisをセッションドライバーとして使い、セッションデータをメモリ上で高速に読み書きする。','difficulty'=>3,'quiz'=>['question'=>'Redisの特徴として正しいものはどれか？','explanation'=>'RedisはデータをRAM上に保持するインメモリDBのため、ディスクベースのDBと比べて読み書き速度が非常に高速。','choices'=>[['body'=>'データをディスクに保存するRDB','is_correct'=>false],['body'=>'データをメモリ上に保持し高速処理するKVS','is_correct'=>true],['body'=>'グラフ構造専用のDB','is_correct'=>false],['body'=>'XML形式のみ格納できるDB','is_correct'=>false]]]],
            ['name'=>'ウィンドウ関数（Window Function）','definition'=>'現在行に関連する行のグループ（ウィンドウ）に対して集計を行う関数。GROUP BYと異なり行を集約せずに結果を返す。','example'=>'RANK() OVER (PARTITION BY dept ORDER BY salary DESC) で部署ごとの給与ランキングを付けられる。','difficulty'=>4,'quiz'=>['question'=>'ウィンドウ関数の特徴として正しいものはどれか？','explanation'=>'ウィンドウ関数はGROUP BYと違い行を集約せず、各行の結果と集計値を同時に取得できる。','choices'=>[['body'=>'GROUP BYと同様に行をまとめる','is_correct'=>false],['body'=>'行を集約せずに集計値を各行に付与できる','is_correct'=>true],['body'=>'JOINの代替として使う','is_correct'=>false],['body'=>'テーブルの行を削除する','is_correct'=>false]]]],
            ['name'=>'EXPLAIN（実行計画）','definition'=>'クエリがどのようにデータを取得するかをDBが示す実行計画。インデックスの使用有無・スキャン方式を確認してチューニングに使う。','example'=>'EXPLAIN SELECT * FROM users WHERE email = \'test@example.com\'; でインデックスが使われているか確認する。','difficulty'=>3,'quiz'=>['question'=>'EXPLAINコマンドの主な用途はどれか？','explanation'=>'EXPLAINはSQLの実行計画を表示し、フルテーブルスキャンやインデックス利用の有無を確認してパフォーマンスチューニングに活用する。','choices'=>[['body'=>'SQLを自動最適化する','is_correct'=>false],['body'=>'SQLの実行計画を表示してチューニングに活用する','is_correct'=>true],['body'=>'インデックスを自動作成する','is_correct'=>false],['body'=>'クエリを実行してデータを返す','is_correct'=>false]]]],
            ['name'=>'ORM（Object-Relational Mapping）','definition'=>'オブジェクト指向言語とRDBのデータ構造の差異を吸収し、SQLを書かずにオブジェクトでDB操作できるフレームワーク。','example'=>'LaravelのEloquentでUser::find(1)とするだけで、SELECT * FROM users WHERE id=1 が実行される。','difficulty'=>2,'quiz'=>['question'=>'ORMの主なメリットはどれか？','explanation'=>'ORMによりSQL文を直接書かずにオブジェクト操作でDBアクセスでき、コードの可読性が向上しRDBMSの差異も吸収できる。','choices'=>[['body'=>'データベースへのアクセス速度を向上させる','is_correct'=>false],['body'=>'SQLを書かずにオブジェクトでDB操作できる','is_correct'=>true],['body'=>'データを自動的に暗号化する','is_correct'=>false],['body'=>'テーブル設計を自動化する','is_correct'=>false]]]],
            ['name'=>'マイグレーション（DB）','definition'=>'データベーススキーマの変更履歴をコードで管理する仕組み。バージョン管理によりチーム間でスキーマを同期できる。','example'=>'LaravelでCreateUsersTableマイグレーションを実行するとusersテーブルが作成され、rollbackで元に戻せる。','difficulty'=>2,'quiz'=>['question'=>'DBマイグレーションの主な目的はどれか？','explanation'=>'マイグレーションはスキーマ変更をコードで管理することで、チーム全員が同じスキーマを再現でき、バージョン管理・ロールバックが可能になる。','choices'=>[['body'=>'データを別DBに移行する','is_correct'=>false],['body'=>'スキーマ変更をコードで管理し再現・ロールバックを可能にする','is_correct'=>true],['body'=>'データをCSVに出力する','is_correct'=>false],['body'=>'クエリを高速化する','is_correct'=>false]]]],
            ['name'=>'データウェアハウス（DWH）','definition'=>'BI・分析目的に特化した大規模データ格納システム。ETLでデータを取り込み、OLAP分析に最適化された構造で格納する。','example'=>'BigQueryやRedshiftに各システムのデータを集約し、経営ダッシュボードの集計クエリを高速実行する。','difficulty'=>4,'quiz'=>['question'=>'データウェアハウスとOLTPデータベースの主な違いはどれか？','explanation'=>'DWHは大量データへの複雑な分析クエリ（OLAP）に最適化。OLTPは個々のトランザクション処理（読み書き）に最適化。','choices'=>[['body'=>'DWHはリアルタイム更新に特化している','is_correct'=>false],['body'=>'DWHは分析クエリ（OLAP）に最適化された大規模ストレージ','is_correct'=>true],['body'=>'DWHはNoSQLの一種','is_correct'=>false],['body'=>'DWHはキャッシュ専用のDB','is_correct'=>false]]]],
            ['name'=>'WAL（Write-Ahead Logging）','definition'=>'データの変更をデータファイルに書く前にまずログ（WAL）に記録する手法。クラッシュリカバリとデータ整合性に不可欠。','example'=>'PostgreSQLはWALを利用し、クラッシュ後もWALログを再生することでデータを復旧する。','difficulty'=>5,'quiz'=>['question'=>'WALの主な目的はどれか？','explanation'=>'WALはデータ変更前にログを先行書き込みすることで、クラッシュが発生しても未コミットデータを正しくロールバック/再適用できる。','choices'=>[['body'=>'クエリを高速化する','is_correct'=>false],['body'=>'クラッシュ時のデータ整合性とリカバリを保証する','is_correct'=>true],['body'=>'データを圧縮する','is_correct'=>false],['body'=>'バックアップを自動化する','is_correct'=>false]]]],
            ['name'=>'集計関数','definition'=>'複数行のデータに対して計算を行いひとつの結果を返す関数。COUNT・SUM・AVG・MAX・MINなどがある。','example'=>'SELECT COUNT(*), AVG(price) FROM products WHERE category_id = 1; でカテゴリ別の件数と平均価格を取得。','difficulty'=>1,'quiz'=>['question'=>'集計関数AVG()の役割はどれか？','explanation'=>'AVGはAverage（平均）の略で、指定列のNULLを除いた値の平均を計算して返す集計関数。','choices'=>[['body'=>'最大値を返す','is_correct'=>false],['body'=>'指定列の平均値を返す','is_correct'=>true],['body'=>'行数を返す','is_correct'=>false],['body'=>'合計値を返す','is_correct'=>false]]]],
            ['name'=>'サブクエリ','definition'=>'別のSQL文の中に入れ子にして書くSELECT文。WHERE句・FROM句・SELECT句など様々な場所で使える。','example'=>'SELECT * FROM users WHERE id IN (SELECT user_id FROM orders WHERE amount > 10000); で高額注文ユーザーを取得。','difficulty'=>3,'quiz'=>['question'=>'相関サブクエリの特徴として正しいものはどれか？','explanation'=>'相関サブクエリは外側クエリの各行に対してサブクエリが実行されるため、外側クエリの列を参照できる。','choices'=>[['body'=>'一度だけ実行される','is_correct'=>false],['body'=>'外側クエリの各行に対して実行され外側の列を参照できる','is_correct'=>true],['body'=>'常にINNER JOINより遅い','is_correct'=>false],['body'=>'FROM句にしか書けない','is_correct'=>false]]]],
            ['name'=>'パーティショニング','definition'=>'大きなテーブルを論理的または物理的に分割してパフォーマンスや管理性を向上させる技術。レンジ・リスト・ハッシュ等の方式がある。','example'=>'売上データをパーティショニングして2024年分は同一パーティション内に収め、古いデータの削除が高速になる。','difficulty'=>4,'quiz'=>['question'=>'テーブルパーティショニングの主なメリットはどれか？','explanation'=>'パーティショニングにより特定パーティションのみをスキャンすることで、大テーブルでのクエリ性能向上とデータ管理が容易になる。','choices'=>[['body'=>'テーブルを複数DBに自動分散する','is_correct'=>false],['body'=>'特定範囲のスキャンを高速化しデータ管理を容易にする','is_correct'=>true],['body'=>'テーブルを結合する','is_correct'=>false],['body'=>'データを暗号化する','is_correct'=>false]]]],
            ['name'=>'コネクションプール','definition'=>'DB接続を事前に確立してプールしておき、リクエストのたびに使い回す仕組み。接続確立のオーバーヘッドを削減する。','example'=>'LaravelのEloquentがコネクションプールを使い、毎回DB接続確立をせず再利用してレスポンスを高速化する。','difficulty'=>3,'quiz'=>['question'=>'コネクションプールを使う主な目的はどれか？','explanation'=>'DB接続の確立にはコストがかかるため、プールで接続を再利用することでオーバーヘッドを減らしスループットを上げる。','choices'=>[['body'=>'データを自動バックアップする','is_correct'=>false],['body'=>'DB接続の再利用でオーバーヘッドを削減する','is_correct'=>true],['body'=>'クエリを最適化する','is_correct'=>false],['body'=>'インデックスを自動生成する','is_correct'=>false]]]],
            ['name'=>'UNIQUE制約','definition'=>'列の値がテーブル内で一意であることを保証する制約。NULLは複数含められる場合もある（DBMSにより異なる）。','example'=>'usersテーブルのemail列にUNIQUE制約を付けることで、同じメールアドレスの重複登録を防ぐ。','difficulty'=>1,'quiz'=>['question'=>'UNIQUE制約が保証することはどれか？','explanation'=>'UNIQUE制約はその列（または列の組み合わせ）に同一の値が2行以上存在しないことを保証する。','choices'=>[['body'=>'値がNULLにならない','is_correct'=>false],['body'=>'列の値がテーブル内で一意である','is_correct'=>true],['body'=>'外部テーブルの行が存在する','is_correct'=>false],['body'=>'値が自動採番される','is_correct'=>false]]]],
            ['name'=>'GROUP BY','definition'=>'指定した列の値でレコードをグループ化し、集計関数と組み合わせて各グループの集計値を求める句。','example'=>'SELECT category_id, COUNT(*) FROM products GROUP BY category_id; でカテゴリ別の商品数を集計する。','difficulty'=>2,'quiz'=>['question'=>'GROUP BYと組み合わせて使うのはどれか？','explanation'=>'GROUP BYで行をグループ化した後、COUNT・SUM・AVGなどの集計関数で各グループの値を集計する。','choices'=>[['body'=>'WHERE句のみ','is_correct'=>false],['body'=>'COUNT・SUMなどの集計関数','is_correct'=>true],['body'=>'JOIN句のみ','is_correct'=>false],['body'=>'ORDER BY句のみ','is_correct'=>false]]]],
            ['name'=>'ETL（Extract Transform Load）','definition'=>'異なるシステムからデータを抽出（E）・変換（T）・ロード（L）してデータウェアハウスに投入するプロセス。','example'=>'夜間バッチでOLTPのMySQLからデータを抽出→日付フォーマット統一・欠損値処理→BigQueryへロードするETLパイプライン。','difficulty'=>4,'quiz'=>['question'=>'ETLのTが示す処理はどれか？','explanation'=>'TransformはETLの中間工程で、抽出したデータを目的のフォーマットや品質に変換する処理。','choices'=>[['body'=>'データを転送する（Transfer）','is_correct'=>false],['body'=>'データを変換する（Transform）','is_correct'=>true],['body'=>'データをテスト（Test）する','is_correct'=>false],['body'=>'データを削除する（Truncate）','is_correct'=>false]]]],
        ]];
    }

    private function algorithmTerms(): array
    {
        return ['algorithm' => [
            ['name'=>'キュー（Queue）','definition'=>'FIFO（先入れ先出し）で動作するデータ構造。先に追加した要素が先に取り出される。BFSや印刷スプールに使われる。','example'=>'タスクキューに仕事を積み、ワーカーが先着順に処理するシステム。','difficulty'=>1,'quiz'=>['question'=>'キューのデータアクセス方式はどれか？','explanation'=>'キューはFIFO（First In First Out：先入れ先出し）方式。スタックはLIFO（後入れ先出し）と対比して覚える。','choices'=>[['body'=>'LIFO（後入れ先出し）','is_correct'=>false],['body'=>'FIFO（先入れ先出し）','is_correct'=>true],['body'=>'ランダムアクセス','is_correct'=>false],['body'=>'優先度順','is_correct'=>false]]]],
            ['name'=>'スタック（Stack）','definition'=>'LIFO（後入れ先出し）で動作するデータ構造。最後に積んだ要素が最初に取り出される。関数呼び出しの管理に利用される。','example'=>'Webブラウザの「戻る」機能は、訪問ページをスタックに積んで管理する。','difficulty'=>1,'quiz'=>['question'=>'スタックのアクセス方式として正しいものはどれか？','explanation'=>'スタックはLIFO（Last In First Out：後入れ先出し）方式。push（積む）とpop（取り出す）操作がある。','choices'=>[['body'=>'FIFO（先入れ先出し）','is_correct'=>false],['body'=>'LIFO（後入れ先出し）','is_correct'=>true],['body'=>'ランダムアクセス','is_correct'=>false],['body'=>'二分探索','is_correct'=>false]]]],
            ['name'=>'二分木（Binary Tree）','definition'=>'各ノードが最大2つの子ノード（左・右）を持つ木構造のデータ構造。二分探索木・ヒープ・構文木などに使われる。','example'=>'数式「(1+2)*3」を二分木で表すと、ルートが「*」、左が「+」（子に1と2）、右が「3」となる。','difficulty'=>3,'quiz'=>['question'=>'二分探索木（BST）の特性として正しいものはどれか？','explanation'=>'BSTでは各ノードについて「左の子孫の値<自分の値<右の子孫の値」が成り立つ。これにより2分探索と同様のO(log n)探索が可能。','choices'=>[['body'=>'全ノードの値が同じ','is_correct'=>false],['body'=>'左の子孫<自分<右の子孫の順序が成り立つ','is_correct'=>true],['body'=>'必ず完全二分木になる','is_correct'=>false],['body'=>'子ノードは1つ以下','is_correct'=>false]]]],
            ['name'=>'ヒープ（Heap）','definition'=>'親ノードの値が常に子ノード以上（最大ヒープ）または以下（最小ヒープ）の完全二分木。優先度キューの実装に使われる。','example'=>'最小ヒープを使った優先度キューでダイクストラ法の「最短距離のノードを取り出す」操作をO(log n)で実現する。','difficulty'=>4,'quiz'=>['question'=>'最小ヒープにおける根（ルート）の値はどれか？','explanation'=>'最小ヒープでは親が常に子以下の値を持つため、ルートには常にヒープ全体の最小値が位置する。','choices'=>[['body'=>'ヒープの中央値','is_correct'=>false],['body'=>'ヒープの最小値','is_correct'=>true],['body'=>'ヒープの最大値','is_correct'=>false],['body'=>'最後に挿入した値','is_correct'=>false]]]],
            ['name'=>'ハッシュテーブル','definition'=>'キーをハッシュ関数でインデックスに変換し、配列に格納するデータ構造。平均O(1)で挿入・検索・削除が可能。','example'=>'Pythonの辞書型（dict）はハッシュテーブルで実装され、d[\'key\']でO(1)アクセスができる。','difficulty'=>3,'quiz'=>['question'=>'ハッシュテーブルの平均的な検索の時間計算量はどれか？','explanation'=>'ハッシュテーブルはキーのハッシュ値でインデックスを直接計算するため、平均O(1)の定数時間でアクセスできる。','choices'=>[['body'=>'O(n)','is_correct'=>false],['body'=>'O(1)','is_correct'=>true],['body'=>'O(log n)','is_correct'=>false],['body'=>'O(n²)','is_correct'=>false]]]],
            ['name'=>'深さ優先探索（DFS）','definition'=>'グラフ・木をできる限り深く進んでからバックトラックする探索アルゴリズム。スタックまたは再帰で実装する。','example'=>'迷路の経路探索でDFSを使うと、1つの道を行き止まりまで進んでから別の分岐を試す。','difficulty'=>3,'quiz'=>['question'=>'DFSの実装で使われるデータ構造はどれか？','explanation'=>'DFSは再帰呼び出し（暗黙のコールスタック）またはスタック（明示的）を使って実装する。','choices'=>[['body'=>'キュー','is_correct'=>false],['body'=>'スタック（または再帰）','is_correct'=>true],['body'=>'ヒープ','is_correct'=>false],['body'=>'ハッシュテーブル','is_correct'=>false]]]],
            ['name'=>'幅優先探索（BFS）','definition'=>'グラフ・木を現在ノードから近い（隣接）ノードから順に探索するアルゴリズム。キューで実装し最短経路探索に使われる。','example'=>'SNSで友人の友人を「つながり距離1→2→3」の順に探索するのはBFSの応用。','difficulty'=>3,'quiz'=>['question'=>'BFSが最短経路探索に適している理由はどれか？','explanation'=>'BFSは各エッジのコストが均一なグラフでスタートから近い順に探索するため、最初に目的地に到達した時がすなわち最短経路。','choices'=>[['body'=>'メモリ使用量が少ない','is_correct'=>false],['body'=>'近い順に探索するため最初の到達が最短経路','is_correct'=>true],['body'=>'再帰で実装できる','is_correct'=>false],['body'=>'スタックを使うから','is_correct'=>false]]]],
            ['name'=>'ダイクストラ法','definition'=>'重み付きグラフの単一始点最短経路を求めるアルゴリズム。優先度キュー（最小ヒープ）を使いO((V+E)log V)で動作する。','example'=>'カーナビがダイクストラ法を使い出発地から目的地まで最短時間（重み付き）ルートを計算する。','difficulty'=>4,'quiz'=>['question'=>'ダイクストラ法の前提条件として正しいものはどれか？','explanation'=>'ダイクストラ法はエッジの重みが負になると正しく動作しない。負の重みがある場合はベルマン-フォード法を使う。','choices'=>[['body'=>'グラフが有向である','is_correct'=>false],['body'=>'エッジの重みが非負である','is_correct'=>true],['body'=>'グラフが木構造である','is_correct'=>false],['body'=>'ノード数が偶数である','is_correct'=>false]]]],
            ['name'=>'マージソート','definition'=>'配列を半分に分割し再帰的にソートしてからマージする分割統治型ソートアルゴリズム。時間計算量は常にO(n log n)。','example'=>'n=8の配列をn=4→2→1に分割してソート済みにし、逆順にマージして全体をソートする。','difficulty'=>3,'quiz'=>['question'=>'マージソートの時間計算量はどれか？','explanation'=>'マージソートは最良・平均・最悪のいずれの場合もO(n log n)の時間計算量を保証する安定ソート。','choices'=>[['body'=>'O(n)','is_correct'=>false],['body'=>'O(n log n)','is_correct'=>true],['body'=>'O(n²)','is_correct'=>false],['body'=>'O(log n)','is_correct'=>false]]]],
            ['name'=>'クイックソート','definition'=>'ピボットを選んで左右に分割する分割統治型ソート。平均O(n log n)だが最悪O(n²)。実用上は最速クラス。','example'=>'Pythonのlist.sort()やCのqsort()の内部でクイックソートの変形（Timsortなど）が使われる。','difficulty'=>3,'quiz'=>['question'=>'クイックソートの最悪時間計算量はどれか？','explanation'=>'クイックソートは既にソート済みの配列などで毎回最小/最大値をピボットに選ぶと、分割が偏りO(n²)になる。','choices'=>[['body'=>'O(n)','is_correct'=>false],['body'=>'O(n log n)','is_correct'=>false],['body'=>'O(n²)','is_correct'=>true],['body'=>'O(log n)','is_correct'=>false]]]],
            ['name'=>'動的計画法（DP）','definition'=>'問題を部分問題に分割し、その解をメモしながら大きな問題を解くアルゴリズム設計技法。重複計算を排除して効率化する。','example'=>'フィボナッチ数列をDPで解くと各計算を1度のみ行いO(n)で完了する（再帰だとO(2^n)）。','difficulty'=>4,'quiz'=>['question'=>'動的計画法が有効な問題の条件はどれか？','explanation'=>'DPは「最適部分構造（部分問題の最適解が全体の最適解を構成）」と「重複する部分問題」の2条件が成り立つ問題に適用できる。','choices'=>[['body'=>'グラフが有向非巡回グラフ（DAG）のみ','is_correct'=>false],['body'=>'重複する部分問題と最適部分構造を持つ問題','is_correct'=>true],['body'=>'入力データがソート済みの問題のみ','is_correct'=>false],['body'=>'問題サイズが小さい場合のみ','is_correct'=>false]]]],
            ['name'=>'貪欲法（Greedy Algorithm）','definition'=>'各ステップで局所的に最適な選択をすることで全体の最適解を求めるアルゴリズム技法。','example'=>'コイン問題（500→100→50→10円の順）や最小全域木のクラスカル法に貪欲法が使われる。','difficulty'=>3,'quiz'=>['question'=>'貪欲法が常に最適解を得られない問題の例はどれか？','explanation'=>'貪欲法は局所最適を積み重ねるが、ナップサック問題（0-1型）では局所最適が全体最適を保証しないためDPが必要。','choices'=>[['body'=>'活動選択問題','is_correct'=>false],['body'=>'0-1ナップサック問題','is_correct'=>true],['body'=>'クラスカル法の最小全域木','is_correct'=>false],['body'=>'ダイクストラ法の最短経路','is_correct'=>false]]]],
            ['name'=>'時間計算量（Big-O記法）','definition'=>'アルゴリズムの入力サイズnに対する処理時間の増加傾向を表す記法。O(1)・O(log n)・O(n)・O(n log n)・O(n²)など。','example'=>'線形探索はO(n)、二分探索はO(log n)、バブルソートはO(n²)で表される。','difficulty'=>2,'quiz'=>['question'=>'O(log n)の時間計算量を持つアルゴリズムはどれか？','explanation'=>'二分探索は毎回探索範囲を半分に絞るため、n=100万でも約20回の比較で済む。これがO(log n)の特性。','choices'=>[['body'=>'線形探索','is_correct'=>false],['body'=>'二分探索','is_correct'=>true],['body'=>'バブルソート','is_correct'=>false],['body'=>'行列積','is_correct'=>false]]]],
            ['name'=>'再帰（Recursion）','definition'=>'関数が自分自身を呼び出す手法。基底ケース（終了条件）と再帰ケースで構成される。木やグラフの処理に自然に表現できる。','example'=>'factorial(n) = n * factorial(n-1)、factorial(0) = 1 と再帰で階乗を定義する。','difficulty'=>2,'quiz'=>['question'=>'再帰関数で必ず必要なものはどれか？','explanation'=>'再帰は無限に呼び出されないよう、必ず再帰を停止させる基底ケース（ベースケース）が必要。ないと無限ループしスタックオーバーフローになる。','choices'=>[['body'=>'グローバル変数','is_correct'=>false],['body'=>'再帰を停止させる基底ケース','is_correct'=>true],['body'=>'ループ文','is_correct'=>false],['body'=>'配列','is_correct'=>false]]]],
            ['name'=>'二分探索（Binary Search）','definition'=>'ソート済み配列の中央値と比較して探索範囲を半分に絞る探索アルゴリズム。O(log n)の高速探索が可能。','example'=>'1〜100の数当てゲームで「50より大きい？小さい？」と毎回半分に絞るのが二分探索の考え方。','difficulty'=>2,'quiz'=>['question'=>'二分探索を適用するための前提条件はどれか？','explanation'=>'二分探索は「中央値と比較して大小で半分に絞る」ため、対象の配列がソート済みであることが必須条件。','choices'=>[['body'=>'データが連結リストである','is_correct'=>false],['body'=>'配列がソート済みである','is_correct'=>true],['body'=>'データが均等に分布している','is_correct'=>false],['body'=>'配列のサイズが偶数である','is_correct'=>false]]]],
            ['name'=>'メモ化（Memoization）','definition'=>'関数の計算結果をキャッシュしておき、同じ引数で再度呼ばれたときはキャッシュを返す最適化手法。再帰＋DPの実装手法。','example'=>'fib(n)を再帰で実装する際、計算済みのfib(k)をdictに保存して重複計算を防ぐ。','difficulty'=>3,'quiz'=>['question'=>'メモ化が最も効果的な場面はどれか？','explanation'=>'メモ化は同じ引数での重複呼び出しが多い再帰関数（例：フィボナッチ・DP）で劇的な性能向上をもたらす。','choices'=>[['body'=>'ソートアルゴリズムの高速化','is_correct'=>false],['body'=>'同じ引数で重複呼び出しされる再帰関数','is_correct'=>true],['body'=>'線形探索の高速化','is_correct'=>false],['body'=>'グラフの辺のコスト削減','is_correct'=>false]]]],
            ['name'=>'バックトラッキング','definition'=>'解候補を試し、条件を満たさない場合は直前の状態に戻って別の候補を試す解探索技法。N Queen問題や数独に適用される。','example'=>'数独の空マスに1〜9を仮入力して矛盾したら戻り、別の数字を試す、を繰り返して解を求める。','difficulty'=>4,'quiz'=>['question'=>'バックトラッキングの特徴として正しいものはどれか？','explanation'=>'バックトラッキングは枝刈りを組み合わせることで、全解の候補すべてを列挙せずに効率的に解を探索できる。','choices'=>[['body'=>'常に最短経路を求める','is_correct'=>false],['body'=>'条件不満足時に直前の状態に戻って別候補を試す','is_correct'=>true],['body'=>'配列のソートに使う','is_correct'=>false],['body'=>'グリーディ法とも呼ばれる','is_correct'=>false]]]],
            ['name'=>'トポロジカルソート','definition'=>'有向非巡回グラフ（DAG）の頂点を、辺の向きを壊さないよう線形に並べるアルゴリズム。依存関係の解決に使われる。','example'=>'ビルドシステムでA→B→Cの依存関係を解析し、コンパイル順序を決定するのにトポロジカルソートを使う。','difficulty'=>4,'quiz'=>['question'=>'トポロジカルソートが適用できるグラフの条件はどれか？','explanation'=>'トポロジカルソートは閉路（サイクル）がない有向非巡回グラフ（DAG）にのみ適用できる。循環依存があると不可能。','choices'=>[['body'=>'無向グラフ','is_correct'=>false],['body'=>'有向非巡回グラフ（DAG）','is_correct'=>true],['body'=>'重み付きグラフ','is_correct'=>false],['body'=>'完全グラフ','is_correct'=>false]]]],
