    private function cloudTerms(): array
    {
        return ['cloud' => [
            ['name'=>'PaaS（Platform as a Service）','definition'=>'OS・ミドルウェア・実行環境を含むプラットフォームをクラウドで提供するサービス形態。アプリ開発に集中できる。','example'=>'Herokuへデプロイするだけでサーバー管理なしにWebアプリを公開できる。','difficulty'=>2,'quiz'=>['question'=>'PaaSの特徴として正しいものはどれか？','explanation'=>'PaaSはOSやミドルウェア管理が不要で開発者はアプリとデータに集中できる。IaaSはインフラも自己管理、SaaSはアプリも提供済み。','choices'=>[['body'=>'OSの管理もユーザーが行う','is_correct'=>false],['body'=>'OS・実行環境はクラウドが管理しアプリ開発に集中できる','is_correct'=>true],['body'=>'アプリケーションもクラウドが提供する','is_correct'=>false],['body'=>'ハードウェアのみ提供される','is_correct'=>false]]]],
            ['name'=>'SaaS（Software as a Service）','definition'=>'ソフトウェアをインターネット経由でサービスとして提供する形態。インストール不要でブラウザで利用できる。','example'=>'Google Workspace・Salesforce・SlackなどがSaaSの代表例。ユーザーはアプリを使うだけ。','difficulty'=>1,'quiz'=>['question'=>'SaaSの説明として正しいものはどれか？','explanation'=>'SaaSはソフトウェアをインターネット経由でサービス提供する形態。ユーザーはインフラ・プラットフォーム・アプリすべてを管理不要。','choices'=>[['body'=>'仮想マシンをクラウドで提供する','is_correct'=>false],['body'=>'完成したソフトウェアをインターネット経由でサービス提供する','is_correct'=>true],['body'=>'開発環境を提供する','is_correct'=>false],['body'=>'物理サーバーをレンタルする','is_correct'=>false]]]],
            ['name'=>'サーバーレス（FaaS）','definition'=>'サーバー管理なしに関数単位でコードを実行するクラウド形態。実行時間のみ課金でスケールは自動。','example'=>'AWS Lambdaに画像リサイズ関数を登録し、S3にアップロードされるたびに自動実行する。','difficulty'=>3,'quiz'=>['question'=>'サーバーレス（FaaS）のメリットとして正しいものはどれか？','explanation'=>'FaaSは実行した分だけ課金・サーバー管理不要・自動スケールが主な利点。ただしコールドスタートのレイテンシが課題。','choices'=>[['body'=>'常時稼働で最速のレスポンスを保証する','is_correct'=>false],['body'=>'サーバー管理不要で実行時間のみ課金される','is_correct'=>true],['body'=>'スケールは手動で行う','is_correct'=>false],['body'=>'ステートフルな処理に最適','is_correct'=>false]]]],
            ['name'=>'Kubernetes（K8s）','definition'=>'コンテナのデプロイ・スケーリング・管理を自動化するオーケストレーションツール。Googleが開発しOSSとして公開。','example'=>'KubernetesのDeploymentで「Podを常に3台維持」と宣言すると、障害時に自動で再起動・再スケジュールされる。','difficulty'=>4,'quiz'=>['question'=>'Kubernetesの主な機能はどれか？','explanation'=>'KubernetesはコンテナをPod単位でスケジュール・管理し、自動スケーリング・自己修復・ローリングアップデートを提供する。','choices'=>[['body'=>'コンテナイメージをビルドする','is_correct'=>false],['body'=>'コンテナのデプロイ・スケーリング・管理を自動化する','is_correct'=>true],['body'=>'ソースコードのバージョン管理','is_correct'=>false],['body'=>'データベースのバックアップ','is_correct'=>false]]]],
            ['name'=>'マイクロサービス','definition'=>'アプリを独立してデプロイ可能な小さなサービス群に分割するアーキテクチャ。各サービスが疎結合で独立スケール可能。','example'=>'ECサイトを「注文サービス・在庫サービス・決済サービス・通知サービス」の独立したマイクロサービスに分割する。','difficulty'=>3,'quiz'=>['question'=>'マイクロサービスのメリットとして最も正しいものはどれか？','explanation'=>'マイクロサービスにより各サービスを独立してデプロイ・スケール・障害分離できるが、サービス間通信の複雑さが増す。','choices'=>[['body'=>'全体のコード量が減少する','is_correct'=>false],['body'=>'各サービスを独立してデプロイ・スケールできる','is_correct'=>true],['body'=>'ネットワーク通信が不要になる','is_correct'=>false],['body'=>'データベースを1つに集約できる','is_correct'=>false]]]],
